 to station","notes":"No station in Stockbridge"}]},"prices":{"summary":"Stockbridge commands a premium over wider SO20 because of its high-street offer and Test Valley setting.","average":"£557,054","detached":"£808,571","semiDetached":"£426,364","terraced":"£345,769","flat":"£152,000","asOf":"2026-04","sourceUrl":"https://www.rightmove.co.uk/house-prices/SO20.html"},"thingsToDo":["Fly-fishing on the upper River Test","Walking the Test Way","Houghton Down / Danebury Hill Fort"],"placesToEat":["The Greyhound on the Test","The Three Cups Inn","The Grosvenor Hotel"],"pros":["Chalk-stream walks on the doorstep","Strong independent retail","Equidistant Andover ↔ Romsey ↔ Winchester"],"cons":["No railway station (nearest: Andover or Winchester)","Premium prices — a destination town, not a commuter dorm","A30 traffic through the High Street at peak times"],"whoItSuits":["Anglers and slow-food households","Buyers prioritising market-town amenities over commuter speed"],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[{"label":"Visit Hampshire — Stockbridge","url":"https://www.visit-hampshire.co.uk/explore/stockbridge-p524261"},{"label":"Orvis UK — Stockbridge store","url":"https://www.orvis.co.uk/pages/stockbridge-store"},{"label":"Robjent''s","url":"http://www.robjents.co.uk/"},{"label":"Ofsted — Stockbridge Primary School","url":"https://reports.ofsted.gov.uk/provider/21/116028"},{"label":"Ofsted — Test Valley School","url":"https://reports.ofsted.gov.uk/provider/23/116430"},{"label":"Rightmove House Prices SO20","url":"https://www.rightmove.co.uk/house-prices/SO20.html"},{"label":"Google Maps — Stockbridge to Winchester","url":"https://www.google.com/maps/dir/Stockbridge,+Hampshire/Winchester"}]},{"id":"stoford-sp2","name":"Stoford","village":"Stoford","town":"Salisbury","county":"Wiltshire","postcode":"SP2","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.04384,"lng":-1.